package org.perq.clan;

import java.time.LocalDateTime;
import java.util.UUID;

public class MemberData {
    private int clanId;
    private UUID player;
    private String role; // Leader, Mod, Member
    private double onlineTime; // in hours
    private LocalDateTime joinedDate;

    // Constructors, getters, setters
    public MemberData() {}

    public MemberData(int clanId, UUID player, String role, double onlineTime, LocalDateTime joinedDate) {
        this.clanId = clanId;
        this.player = player;
        this.role = role;
        this.onlineTime = onlineTime;
        this.joinedDate = joinedDate;
    }

    // Getters and setters
    public int getClanId() { return clanId; }
    public void setClanId(int clanId) { this.clanId = clanId; }

    public UUID getPlayer() { return player; }
    public void setPlayer(UUID player) { this.player = player; }

    public String getRole() { return role; }
    public void setRole(String role) { this.role = role; }

    public double getOnlineTime() { return onlineTime; }
    public void setOnlineTime(double onlineTime) { this.onlineTime = onlineTime; }

    public LocalDateTime getJoinedDate() { return joinedDate; }
    public void setJoinedDate(LocalDateTime joinedDate) { this.joinedDate = joinedDate; }
}
